import { isString } from 'lodash-es';

/**
 * Map to define with features are associated.
 * Example: Direction indicator feature is associated to connection feature
 */
const ASSOCIATED_FEATURES_MAP: Record<string, string[]> = {
  connection: ['direction-start', 'direction-end'],
};

/**
 * Iterates over the associated feature identifiers to check if a feature is an associated feature of another one.
 * @param featureId -
 */
export const isAssociatedFeature = (featureId: string | number) => {
  if (!isString(featureId)) {
    return false;
  }

  const associatedFeatureIdentifiers = ASSOCIATED_FEATURES_MAP.connection;

  for (const associatedFeatureIdentifier of associatedFeatureIdentifiers) {
    if (featureId.includes(associatedFeatureIdentifier)) {
      return true;
    }
  }

  return false;
};

/**
 * Checks whether a feature has associated features (as for now, just connection features have)
 * @param featureId -
 */
export const hasAssociatedFeatures = (featureId: string) => {
  return featureId.includes('connection');
};

export const getAssociatedFeatures = (associatedFeatureIdentifier: string) =>
  ASSOCIATED_FEATURES_MAP[associatedFeatureIdentifier] ?? [];
